class TransactionEvent:
    """Represents a financial transaction event."""

    def __init__(self, data: Dict[str, Any]):
        self.transaction_id = data.get('transaction_id')
        self.event_type = data.get('event_type')
        self.amount = data.get('amount', 0.0)
        self.currency = data.get('currency', 'USD')
        self.sender_account = data.get('sender_account')
        self.receiver_account = data.get('receiver_account')
        self.timestamp = data.get('timestamp', datetime.utcnow().isoformat())
        self.metadata = data.get('metadata', {})
        self.status = data.get('status', 'pending')
        self.raw_data = data

    def __repr__(self):
        return (
            f"TransactionEvent(id={self.transaction_id}, "
            f"type={self.event_type}, amount={self.amount} {self.currency}, "
            f"status={self.status})"
        )


class FraudDetectionService:
    """Simple fraud detection logic."""

    HIGH_VALUE_THRESHOLD = 10000.0
    SUSPICIOUS_COUNTRIES = {'XX', 'YY', 'ZZ'}

    @staticmethod
    def check_transaction(event: TransactionEvent) -> Dict[str, Any]:
        alerts = []
        risk_score = 0.0

        # High value transaction check
        if event.amount > FraudDetectionService.HIGH_VALUE_THRESHOLD:
            alerts.append(f"High value transaction: {event.amount} {event.currency}")
            risk_score += 0.4

        # Suspicious country check
        country = event.metadata.get('country', '')
        if country in FraudDetectionService.SUSPICIOUS_COUNTRIES:
            alerts.append(f"Transaction from suspicious country: {country}")
            risk_score += 0.5

        # Rapid successive transactions check
        if event.metadata.get('transactions_last_hour', 0) > 20:
            alerts.append("Unusually high transaction frequency")
            risk_score += 0.3

        # Negative or zero amount
        if event.amount <= 0:
            alerts.append(f"Invalid transaction amount: {event.amount}")
            risk_score += 0.8

        return {
            'transaction_id': event.transaction_id,
            'risk_score': min(risk_score, 1.0),
            'alerts': alerts,
            'flagged': risk_score >= 0.5
        }


class TransactionHandlerRegistry:
    """Registry for dynamic message handlers based on event type."""

    def __init__(self):
        self._handlers: Dict[str, list[Callable]] = {}
        self._default_handler: Optional[Callable] = None

    def register(self, event_type: str):
        """Decorator to register a handler for a specific event type."""
        def decorator(func: Callable):
            if event_type not in self._handlers:
                self._handlers[event_type] = []
            self._handlers[event_type].append(func)
            logger.info(f"Registered handler '{func.__name__}' for event type '{event_type}'")
            return func
        return decorator

    def set_default_handler(self, func: Callable):
        """Set a default handler for unregistered event types."""
        self._default_handler = func
        return func

    def get_handlers(self, event_type: str) -> list[Callable]:
        """Get all handlers for a given event type."""
        handlers = self._handlers.get(event_type, [])
        if not handlers and self._default_handler:
            return [self._default_handler]
        return handlers

    @property
    def registered_types(self):
        return list(self._handlers.keys())


# Global handler registry
handler_registry = TransactionHandlerRegistry()


# --- Transaction Handlers ---

@handler_registry.register('payment')
def handle_payment(event: TransactionEvent) -> Dict[str, Any]:
    """Process payment transactions."""
    logger.info(f"Processing payment: {event.transaction_id} - "
                f"{event.amount} {event.currency} from {event.sender_account} to {event.receiver_account}")

    # Business logic for payments
    result = {
        'transaction_id': event.transaction_id,
        'action': 'payment_processed',
        'status': 'completed',
        'processed_at': datetime.utcnow().isoformat()
    }

    # Run fraud check
    fraud_result = FraudDetectionService.check_transaction(event)
    if fraud_result['flagged']:
        result['status'] = 'held_for_review'
        result['fraud_alerts'] = fraud_result['alerts']
        result['risk_score'] = fraud_result['risk_score']
        logger.warning(f"Payment {event.transaction_id} flagged for fraud review: {fraud_result['alerts']}")

    return result


@handler_registry.register('withdrawal')
def handle_withdrawal(event: TransactionEvent) -> Dict[str, Any]:
    """Process withdrawal transactions."""
    logger.info(f"Processing withdrawal: {event.transaction_id} - "
                f"{event.amount} {event.currency} from {event.sender_account}")

    # Business logic for withdrawals
    fraud_result = FraudDetectionService.check_transaction(event)

    if fraud_result['flagged']:
        logger.warning(f"Withdrawal {event.transaction_id} blocked due to fraud risk: {fraud_result['alerts']}")
        return {
            'transaction_id': event.transaction_id,
            'action': 'withdrawal_blocked',
            'status': 'blocked',
            'reason': 'fraud_detected',
            'fraud_alerts': fraud_result['alerts'],
            'risk_score': fraud_result['risk_score'],
            'processed_at': datetime.utcnow().isoformat()
        }

    return {
        'transaction_id': event.transaction_id,
        'action': 'withdrawal_processed',
        'status': 'completed',
        'processed_at': datetime.utcnow().isoformat()
    }


