class MessageDeserializer:
    """Handles deserialization of incoming messages."""

    @staticmethod
    def deserialize_json(raw_bytes: bytes) -> Dict[str, Any]:
        """Deserialize JSON bytes to dictionary."""
        try:
            return json.loads(raw_bytes.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            logger.error(f"Failed to deserialize message: {e}")
            raise

    @staticmethod
    def deserialize_to_event(raw_bytes: bytes) -> TransactionEvent:
        """Deserialize raw bytes to TransactionEvent."""
        data = MessageDeserializer.deserialize_json(raw_bytes)
        return TransactionEvent(data)


class TransactionProcessingMetrics:
    """Simple metrics tracking for transaction processing."""

    def __init__(self):
        self.total_processed = 0
        self.total_errors = 0
        self.by_event_type: Dict[str, int] = {}
        self.by_status: Dict[str, int] = {}
        self.flagged_transactions = 0
        self.start_time = datetime.utcnow()

    def record_processed(self, event_type: str, result: Dict[str, Any]):
        self.total_processed += 1
        self.by_event_type[event_type] = self.by_event_type.get(event_type, 0) + 1
        status = result.get('status', 'unknown')
        self.by_status[status] = self.by_status.get(status, 0) + 1
        if result.get('fraud_alerts'):
            self.flagged_transactions += 1

    def record_error(self):
        self.total_errors += 1

    def get_summary(self) -> Dict[str, Any]:
        uptime = (datetime.utcnow() - self.start_time).total_seconds()
        return {
            'total_processed': self.total_processed,
            'total_errors': self.total_errors,
            'flagged_transactions': self.flagged_transactions,
            'by_event_type': dict(self.by_event_type),
            'by_status': dict(self.by_status),
            'uptime_seconds': uptime,
            'throughput_per_second': self.total_processed / max(uptime, 1)
        }


class FinancialTransactionConsumer:
    """
    Kafka consumer for processing financial transaction events.
    Consumes messages from configured topics, deserializes them,
    and routes to appropriate handlers based on event type.
    """

    def __init__(
        self,
        bootstrap_servers: str = 'localhost:9092',
        topics: Optional[list[str]] = None,
        group_id: str = 'transaction-processing-group',
        auto_offset_reset: str = 'earliest',
        enable_auto_commit: bool = False,
        max_poll_records: int = 500,
        session_timeout_ms: int = 30000,
        heartbeat_interval_ms: int = 10000,
        **kwargs
    ):
        self.topics = topics or ['financial-transactions']
        self.metrics = TransactionProcessingMetrics()
        self._running = False
        self._consumer = None

        consumer_config = {
            'bootstrap_servers': bootstrap_servers,
            'group_id': group_id,
            'auto_offset_reset': auto_offset_reset,
            'enable_auto_commit': enable_auto_commit,
            'max_poll_records': max_poll_records,
            'session_timeout_ms': session_timeout_ms,
            'heartbeat_interval_ms': heartbeat_interval_ms,
            'value_deserializer': lambda m: m,  # Raw bytes, we handle deserialization
            'key_deserializer': lambda k: k.decode('utf-8') if k else None,
        }
        consumer_config.update(kwargs)

        try:
            self._consumer = KafkaConsumer(**consumer_config)
            self._consumer.subscribe(self.topics)
            logger.info(f"Consumer initialized. Subscribed to topics: {self.topics}")
            logger.info(f"Registered event handlers: {handler_registry.registered_types}")
        except KafkaError as e:
            logger.error(f"Failed to initialize Kafka consumer: {e}")
            raise

    def _process_message(self, message) -> Optional[Dict[str, Any]]:
        """Process a single Kafka message."""
        try:
            # Deserialize message to TransactionEvent
            event = MessageDeserializer.deserialize_to_event(message.value)
            logger.info(f"Received event: {event}")

            # Get handlers for this event type
            handlers = handler_registry.get_handlers(event.event_type)

            if not handlers:
                logger.warning(f"No handler found for event type: {event.event_type}")
                self.metrics.record_error()
                return None

            # Execute all registered handlers for this event type
            results = []
            for handler in handlers:
                try:
                    result = handler(event)
                    results.append(result)
                    self.metrics.record_processed(event.event_type, result)
                    logger.info(f"Handler '{handler.__name__}' result for {event.transaction_id}: "
                                f"status={result.get('status')}")
                except Exception as handler_err:
                    logger.error(f"Handler '{handler.__name__}' failed for "
                                 f"{event.transaction_id}: {handler_err}", exc_info=True)
                    self.metrics.record_error()

            # Return the last result (or aggregate if needed)
            return results[-1] if results else None

        except json.JSONDecodeError as e:
            logger.error(f"Failed to deserialize message from partition {message.partition} "
                         f"offset {message.offset}: {e}")
            self.metrics.record_error()
            return None
        except Exception as e:
            logger.error(f"Unexpected error processing message: {e}", exc_info=True)
            self.metrics.record_error()
            return None

    def start(self):
        """Start consuming and processing messages."""
        self._running = True
        logger.info("Starting transaction consumer...")

        # Set up graceful shutdown
        signal.signal(signal.SIGINT, self._signal_handler)
        signal.signal(signal.SIGTERM, self._signal_handler)

        try:
            while self._running:
                # Poll for messages
                message_batch = self._consumer.poll(timeout_ms=1000)

                for topic_partition, messages in message_batch.items():
                    for message in messages:
                        logger.debug(
                            f"Message from {topic_partition.topic}[{topic_partition.partition}] "
                            f"offset={message.offset}"
                        )
                        self._process_message(message)

                # Commit offsets after processing batch
                if message_batch:
                    try:
                        self._consumer.commit()
                    except KafkaError as e:
                        logger.error(f"Failed to commit offsets: {e}")

                # Periodic metrics logging
                if self.metrics.total_processed > 0 and self.metrics.total_processed % 100 == 0:
                    logger.info(f"Metrics summary: {json.dumps(self.metrics.get_summary(), indent=2)}")

        except Exception as e:
            logger.error(f"Consumer loop error: {e}", exc_info=True)
        finally:
            self._shutdown()

    def _signal_handler(self, signum, frame):
        """Handle shutdown signals gracefully."""
        logger.info(f"Received signal {signum}. Initiating graceful shutdown...")
        self._running = False

    def _shutdown(self):
        """Clean up resources."""
        logger.info("Shutting down consumer...")
        if self._consumer:
            try:
                self._consumer.commit()
                logger.info("Final offset commit successful")
            except Exception as e:
                logger.error(f"Error during final commit: {e}")
            finally:
                self._consumer.close()
                logger.info("Consumer closed")

        # Log final metrics
        summary = self.metrics.get_summary()
        logger.info(f"Final metrics:\n{json.dumps(summary, indent=2)}")

    def stop(self):
        """Stop the consumer."""
        self._running = False


