def run_demo_processing():
    """
    Demonstrate message processing without a live Kafka broker.
    Processes sample messages through the handler pipeline.
    """
    logger.info("=" * 60)
    logger.info("Running demo processing (no Kafka broker required)")
    logger.info("=" * 60)

    metrics = TransactionProcessingMetrics()
    sample_messages = create_sample_messages()

    for msg_data in sample_messages:
        logger.info("-" * 40)
        # Simulate serialization/deserialization
        raw_bytes = json.dumps(msg_data).encode('utf-8')
        event = MessageDeserializer.deserialize_to_event(raw_bytes)
        logger.info(f"Processing: {event}")

        handlers = handler_registry.get_handlers(event.event_type)
        for handler in handlers:
            try:
                result = handler(event)
                metrics.record_processed(event.event_type, result)
                logger.info(f"Result: {json.dumps(result, indent=2)}")
            except Exception as e:
                logger.error(f"Handler error: {e}")
                metrics.record_error()

    logger.info("=" * 60)
    logger.info(f"Processing Summary:\n{json.dumps(metrics.get_summary(), indent=2)}")
    logger.info("=" * 60)


